import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useLocation } from 'react-router-dom';
import { FiMessageCircle, FiX, FiSend, FiMinimize2, FiMaximize2, FiMic, FiMicOff, FiVolume2, FiVolumeX } from 'react-icons/fi';
import { projects } from '../data/projects';
import Button from './Button';

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
  timestamp: Date;
  type?: 'text' | 'quick-reply' | 'suggestion' | 'error';
  isTyping?: boolean;
}

interface AIChatbotProps {
  className?: string;
}

// Knowledge base for the AI assistant
const knowledgeBase = {
  profile: {
    name: 'Aminul Islam Bhuiyan Amin',
    role: 'AI-driven Computer Science Student',
    university: 'BUBT',
    about:
      'AI-driven Computer Science student at BUBT, deeply passionate about building intelligent systems. Interests lie in Deep Learning, NLP, and LLMs — with hands-on experience using PyTorch, TensorFlow, and Hugging Face. Currently exploring prompt engineering, multimodal AI, and LangChain-based applications.',
  },
  quickReplies: [
    { text: 'Tell me about your projects', action: 'projects' },
    { text: 'What are your skills?', action: 'skills' },
    { text: 'Show me your blog posts', action: 'blog' },
    { text: 'How can I contact you?', action: 'contact' },
    { text: "What's your background?", action: 'about' },
  ],
};

// Basic type definitions for Web Speech API
interface SpeechRecognitionEvent {
  results: {
    [index: number]: {
      [index: number]: {
        transcript: string;
      };
    };
  };
}

interface SpeechRecognitionErrorEvent {
  error: string;
}

export const AIChatbot: React.FC<AIChatbotProps> = ({ className = '' }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  
  // Voice Mode State
  const [isListening, setIsListening] = useState(false);
  const [voiceEnabled, setVoiceEnabled] = useState(false);
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const recognitionRef = useRef<any>(null); 

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-US';

      recognitionRef.current.onresult = (event: SpeechRecognitionEvent) => {
        const transcript = event.results[0][0].transcript;
        setInputValue(transcript);
        handleSendMessage(transcript); // Auto-send on voice end
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };

      recognitionRef.current.onerror = (event: SpeechRecognitionErrorEvent) => {
        console.error('Speech recognition error', event.error);
        setIsListening(false);
      };
    }
    // eslint-disable-next-line
  }, []);

  const toggleVoiceInput = () => {
    if (!recognitionRef.current) {
      alert('Voice input is not supported in this browser.');
      return;
    }

    if (isListening) {
      recognitionRef.current.stop();
    } else {
      recognitionRef.current.start();
      setIsListening(true);
    }
  };

  const speakResponse = (text: string) => {
    if (!voiceEnabled || !('speechSynthesis' in window)) return;
    
    // Cancel current speech
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    // Try to find a good English voice
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(v => v.name.includes('Google US English')) || voices.find(v => v.lang === 'en-US');
    if (preferredVoice) utterance.voice = preferredVoice;
    
    utterance.rate = 1;
    utterance.pitch = 1;
    window.speechSynthesis.speak(utterance);
  };

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isOpen]);

  const location = useLocation();

  // Context-aware initialization
  useEffect(() => {
    if (isOpen && messages.length === 0) {
      setIsTyping(true);
      
      let greeting = "Hi! I'm Aminul's AI Assistant. How can I help you today?";
      let suggestions = knowledgeBase.quickReplies;

      // Project Context
      if (location.pathname.startsWith('/projects/') && location.pathname.length > 10) {
        greeting = "I see checking out one of my projects! I can explain the architecture, tech stack, or key challenges provided in this project.";
        suggestions = [
          { text: 'Explain Architecture', action: 'project_arch' },
          { text: 'Tech Stack?', action: 'project_stack' },
          ...knowledgeBase.quickReplies.slice(0, 3)
        ];
      }
      // Blog Context
      else if (location.pathname.startsWith('/blog')) {
        greeting = "Looking for technical insights? I can recommend articles or summarize my writing topics.";
        suggestions = [
          { text: 'Latest Articles', action: 'blog' },
          { text: 'Topics', action: 'skills' },
          ...knowledgeBase.quickReplies.slice(0, 3)
        ];
      }
      // Contact Context
      else if (location.pathname === '/contact') {
        greeting = "Want to get in touch? I can help you find the best channel to reach Aminul.";
        suggestions = [
          { text: 'Email', action: 'contact' },
          { text: 'LinkedIn', action: 'contact' },
        ];
      }

      setTimeout(() => {
        setMessages([
          {
            id: 'init-1',
            text: greeting,
            sender: 'bot',
            timestamp: new Date(),
            type: 'text',
          },
          {
            id: 'init-2',
            text: JSON.stringify(suggestions),
            sender: 'bot',
            timestamp: new Date(),
            type: 'quick-reply',
          },
        ]);
        setIsTyping(false);
      }, 1000);
    }
  }, [isOpen, messages.length, location.pathname]);

  const generateResponse = (userMessage: string) => {
    const message = userMessage.toLowerCase();

    // Fuzzy matching helper
    const matches = (keywords: string[]) => keywords.some((k) => message.includes(k));

    // Context-Aware: Project Details
    if (location.pathname.startsWith('/projects/') && location.pathname.length > 10) {
      const slug = location.pathname.split('/').pop();
      const currentProject = projects.find(
        (p) => p.title.replace(/\s+/g, '-').toLowerCase() === slug
      );

      if (currentProject) {
        if (matches(['stack', 'tech', 'built', 'language', 'framework'])) {
          return {
            text: `This project is built with: ${currentProject.tags.join(', ')}. It leverages these technologies to solve the core problem efficiently.`,
            quickReplies: [
              { text: 'Key challenges?', action: 'project_challenges' },
              { text: 'Architecture?', action: 'project_arch' },
              { text: 'Back to all projects', action: 'projects' }
            ],
          };
        }
        if (matches(['architecture', 'design', 'structure', 'how', 'arch'])) {
           return {
            text: `The architecture focuses on ${currentProject.tags[0]} principles. ${currentProject.description.split('.')[0]}. Check the GitHub repo for the full system diagram!`,
             quickReplies: [{ text: 'View Code', action: 'contact' }] // Placeholder action
           }
        }
        if (matches(['challenge', 'problem', 'difficult'])) {
           return {
             text: `One key challenge was optimizing performance and ensuring scalability. ` + (currentProject.highlights?.[0] || ''),
             quickReplies: [{ text: 'Tech Stack', action: 'project_stack' }]
           }
        }
      }
    }

    // Project related queries
    if (matches(['project', 'work', 'build', 'made', 'portfolio', 'app'])) {
      return {
        text: `I've built some cool things! Here are a few highlights:\n\n${projects
          .slice(0, 3)
          .map((p) => `• ${p.title}`)
          .join('\n')}`,
        quickReplies: [
          { text: 'View all projects', action: 'projects' },
          { text: 'Tell me about skills', action: 'skills' },
        ],
      };
    }

    // Skills/Stack related queries
    if (
      matches([
        'skill',
        'tech',
        'stack',
        'language',
        'program',
        'code',
        'react',
        'python',
        'learn',
        'expert',
      ])
    ) {
      return {
        text: 'My technical toolkit includes:\n• Languages: Python, TypeScript, JavaScript\n• Frameworks: React, PyTorch, TensorFlow\n• Focus: Deep Learning, NLP, & Web Development',
        quickReplies: [
          { text: 'See my projects', action: 'projects' },
          { text: 'Contact me', action: 'contact' },
        ],
      };
    }

    // Contact related queries
    if (matches(['contact', 'email', 'hire', 'reach', 'touch', 'message', 'talk'])) {
      return {
        text: "I'd love to connect! You can reach me via email or LinkedIn. Check out the footer for direct links!",
        quickReplies: [{ text: 'Back to start', action: 'about' }],
      };
    }

    // Blog related queries
    if (matches(['blog', 'article', 'read', 'write', 'post', 'news'])) {
      return {
        text: 'I write about AI and Tech. You can read my latest deep dives on the Blog page.',
        quickReplies: [{ text: 'Go to Blog', action: 'blog' }],
      };
    }

    // Identity/About queries
    if (matches(['who', 'name', 'about', 'student', 'background', 'intro', 'hi', 'hello', 'hey'])) {
      return {
        text: "Hi! I'm Aminul Islam Bhuiyan Amin, an AI-driven Computer Science student at BUBT. I love building intelligent systems. How can I help?",
        quickReplies: [
          { text: 'What are your skills?', action: 'skills' },
          { text: 'Show me projects', action: 'projects' },
        ],
      };
    }

    return {
      text: "I'm not sure about that, but I can tell you about my projects, skills, or background. What interests you?",
      quickReplies: knowledgeBase.quickReplies,
    };
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim()) return;

    // User Message
    const userMessage: Message = {
      id: Date.now().toString(),
      text: text.trim(),
      sender: 'user',
      timestamp: new Date(),
      type: 'text',
    };

    setMessages((prev) => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    // Simulate AI delay
    setTimeout(() => {
      const response = generateResponse(text);

      const botMessage: Message = {
        id: (Date.now() + 1).toString(),
        text: response.text,
        sender: 'bot',
        timestamp: new Date(),
        type: 'text',
      };

      setIsTyping(false);
      setMessages((prev) => [...prev, botMessage]);
      
      // Voice Output
      speakResponse(response.text);

      if (response.quickReplies) {
        setMessages((prev) => [
          ...prev,
          {
            id: (Date.now() + 2).toString(),
            text: JSON.stringify(response.quickReplies),
            sender: 'bot',
            timestamp: new Date(),
            type: 'quick-reply',
          },
        ]);
      }
    }, 1000);
  };

  const handleQuickReply = (action: string) => {
    // Handle navigation or specific actions here
    if (action === 'projects') handleSendMessage('Tell me about your projects');
    if (action === 'skills') handleSendMessage('What are your skills?');
    if (action === 'blog') handleSendMessage('Show me blog posts');
    if (action === 'contact') handleSendMessage('How can I contact you?');
    if (action === 'about') handleSendMessage("What's your background?");
    
    // Context specific
    if (action === 'project_stack') handleSendMessage('What technologies are used in this project?');
    if (action === 'project_arch') handleSendMessage('How was this project built?');
  };

  return (
    <>
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{
              opacity: 1,
              y: 0,
              scale: 1,
              height: isMinimized ? 'auto' : '500px',
              width: isMinimized ? '300px' : '350px',
            }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            className={`fixed bottom-24 right-4 sm:right-6 glass-card rounded-2xl shadow-2xl overflow-hidden z-[70] border border-gray-200 dark:border-gray-700 flex flex-col ${className}`}
          >
            {/* Header */}
            <div className="p-4 bg-primary text-white flex justify-between items-center bg-gradient-to-r from-primary to-indigo-600">
              <div className="flex items-center gap-2">
                <FiMessageCircle className="w-5 h-5" />
                <span className="font-semibold">AI Assistant</span>
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setIsMinimized(!isMinimized)}
                  className="p-1 hover:bg-white/20 rounded-full transition-colors"
                  aria-label={isMinimized ? 'Maximize chat' : 'Minimize chat'}
                >
                  {isMinimized ? (
                    <FiMaximize2 className="w-4 h-4" />
                  ) : (
                    <FiMinimize2 className="w-4 h-4" />
                  )}
                </button>
                <button
                  onClick={() => setIsOpen(false)}
                  className="p-1 hover:bg-white/20 rounded-full transition-colors"
                  aria-label="Close chat"
                >
                  <FiX className="w-4 h-4" />
                </button>
              </div>
            </div>

            {!isMinimized && (
              <>
                {/* Messages Area */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4 glass-card">
                  {messages.map((msg) => (
                    <div
                      key={msg.id}
                      className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                    >
                      {msg.type === 'quick-reply' ? (
                        <div className="flex flex-wrap gap-2 max-w-[85%]">
                          {JSON.parse(msg.text).map(
                            (reply: { text: string; action: string }, idx: number) => (
                              <button
                                key={idx}
                                onClick={() => handleQuickReply(reply.action)}
                                className="text-xs glass-card text-primary border border-primary/20 px-3 py-1.5 rounded-full hover:bg-primary/5 transition-colors shadow-sm"
                              >
                                {reply.text}
                              </button>
                            )
                          )}
                        </div>
                      ) : (
                        <div
                          className={`max-w-[80%] p-3 rounded-2xl ${
                            msg.sender === 'user'
                              ? 'bg-primary text-white rounded-br-none'
                              : 'glass-card text-[var(--theme-text-primary)] rounded-bl-none shadow-sm border border-gray-200 dark:border-gray-700'
                          }`}
                        >
                          <p className="text-sm whitespace-pre-line">{msg.text}</p>
                          <span className="text-[10px] opacity-70 mt-1 block">
                            {msg.timestamp.toLocaleTimeString([], {
                              hour: '2-digit',
                              minute: '2-digit',
                            })}
                          </span>
                        </div>
                      )}
                    </div>
                  ))}
                  {isTyping && (
                    <div className="flex justify-start">
                      <div className="glass-card p-3 rounded-2xl rounded-bl-none shadow-sm border border-gray-200 dark:border-gray-700">
                        <div className="flex gap-1">
                          <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" />
                          <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-100" />
                          <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-200" />
                        </div>
                      </div>
                    </div>
                  )}
                  <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <div className="p-3 glass-card border-t border-gray-200 dark:border-gray-700">
                  <div className="flex gap-2 items-end">
                    <div className="relative flex-1">
                      <input
                        ref={inputRef}
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyPress={(e) => e.key === 'Enter' && handleSendMessage(inputValue)}
                        placeholder={isListening ? 'Listening...' : "Type a message..."}
                        className={`w-full glass-card border-0 rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-primary/50 ${isListening ? 'animate-pulse ring-2 ring-red-500/50' : ''}`}
                      />
                      {/* Voice Indicator Pulse */}
                      <AnimatePresence>
                        {isListening && (
                          <motion.span
                            initial={{ scale: 0, opacity: 0 }}
                            animate={{ scale: 1.2, opacity: 0.5 }}
                            exit={{ scale: 0, opacity: 0 }}
                            transition={{ repeat: Infinity, duration: 1 }}
                            className="absolute right-3 top-1/2 -translate-y-1/2 w-2 h-2 bg-red-500 rounded-full"
                          />
                        )}
                      </AnimatePresence>
                    </div>

                    {/* Voice Input Button */}
                    <Button
                      onClick={toggleVoiceInput}
                      className={`!p-2 !rounded-xl aspect-square flex items-center justify-center transition-colors ${
                        isListening ? 'bg-red-500 hover:bg-red-600 text-white' : 'bg-gray-100 dark:bg-gray-700 text-[var(--theme-text-primary)] text-opacity-60'
                      }`}
                      aria-label="Toggle voice input"
                      variant="ghost"
                    >
                      {isListening ? <FiMicOff className="w-4 h-4" /> : <FiMic className="w-4 h-4" />}
                    </Button>

                    <Button
                      onClick={() => handleSendMessage(inputValue)}
                      className="!p-2 !rounded-xl aspect-square flex items-center justify-center"
                      disabled={!inputValue.trim()}
                      aria-label="Send message"
                    >
                      <FiSend className="w-4 h-4" />
                    </Button>
                  </div>
                  
                  {/* Voice Options */}
                  <div className="flex justify-end mt-2">
                     <button 
                       onClick={() => setVoiceEnabled(!voiceEnabled)}
                       className={`flex items-center gap-1.5 text-[10px] font-medium transition-colors ${voiceEnabled ? 'text-primary' : 'text-[var(--theme-text-primary)] text-opacity-70'}`}
                     >
                       {voiceEnabled ? <FiVolume2 className="w-3 h-3" /> : <FiVolumeX className="w-3 h-3" />}
                       {voiceEnabled ? 'Voice Response On' : 'Voice Response Off'}
                     </button>
                  </div>
                </div>
              </>
            )}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Notification Bubble */}
      <AnimatePresence>
        {!isOpen && !messages.length && (
          <motion.div
            initial={{ opacity: 0, x: 20, scale: 0.9 }}
            animate={{ opacity: 1, x: 0, scale: 1 }}
            exit={{ opacity: 0, x: 10, scale: 0.9 }}
            className="fixed bottom-8 right-20 sm:right-24 z-[70] pointer-events-none"
          >
            <div className="glass-card px-4 py-2 rounded-xl flex items-center gap-2">
              <span className="text-sm font-medium whitespace-nowrap text-[var(--theme-text-primary)]">Need help? 👋</span>
              {/* Arrow */}
              <div className="absolute -right-1.5 top-1/2 -translate-y-1/2 w-3 h-3 glass-card transform rotate-45" />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Toggle Button */}
      <motion.button
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        onClick={() => setIsOpen(!isOpen)}
        className={`p-3.5 sm:p-4 rounded-[28px] sm:rounded-full shadow-[0_10px_40px_rgba(0,0,0,0.4)] border transition-all duration-300 backdrop-blur-[15px] z-[60] ${
          isOpen ? 'bg-[var(--glass-bg)] border-[var(--glass-border)] text-[var(--theme-text-primary)]' : 'bg-gradient-to-tr from-[#ec4899] to-[#8b5cf6] border-white/20 text-white hover:from-[#f472b6] hover:to-[#a78bfa]'
        }`}
        style={{ backdropFilter: 'var(--glass-blur)' }}
        aria-label={isOpen ? 'Close chat assistant' : 'Open chat assistant'}
      >
        {isOpen ? <FiX className="w-5 h-5 sm:w-6 sm:h-6" /> : <FiMessageCircle className="w-5 h-5 sm:w-6 sm:h-6" />}
      </motion.button>
    </>
  );
};
